//获取赛事列表
message MatchListReq {
    int32 game_id = 1;      //游戏id
    uint32 uid = 2;         //玩家id
    TagType tag_type = 3;   //ALL Cash Free Registered
    int32 push_num = 4;     //推送次数
    int32 agency_id = 5;    //分盘 id
}

enum TagType
{
    TAG_ALL = 0;
    TAG_CASH = 1;
    TAG_FREE = 2;
    TAG_REGIST = 3;
}

enum UserStatus
{
    NO_REGIST = 0;  //未报名
    REGIST = 1;     //已报名
    ELIMINATED = 2; //已淘汰
}

enum MatchStatus
{
    DEFORE = 0; //没开赛  
    BEGIN = 1;  //开赛
    END = 2;    //已结束   
}

enum MatchType
{
    NONE = 0;
    TIMIGN = 1;         //定时赛
    PLAYER_FULL = 2;    //人满赛
}

enum MatchTag
{
    MT_NONE = 0;
    MT_GENERAL = 1;     //通用赛
    MT_DAY = 2;         //日赛
    MT_WEEK = 3;        //周赛
    MT_MONTH = 4;       //月赛
}

enum MatchForm
{
    MF_NONE = 0;
    MF_FREE = 1;        //免费赛
    MF_CHAM= 2;         //锦标赛
    MF_CASH = 3;        //收费赛
}

message Prop
{
    int64 id = 1;       //道具id
    int64 num = 2;      //道具数量
    int32 type = 3;     //道具类型
}

message FastMatchInfo
{
    bool fast = 1;                          //是否快速赛
    int32 operate_time = 2;                 //玩家在其回合结束前有 {xx} 秒的时间行动
    int32 first_player_operate_time = 3;    //先手玩家有 {xx} 秒的时间行动
    int32 combine_card_time = 4;            //所有玩家有 {xx} 秒的时间组合自己的牌
}

message MatchInfo {
    int64 match_config_id = 1;      //赛事配置id
    string match_instance_id = 2;   //赛事实例id
    string match_name = 3;          //赛事名称
    string match_pic = 4;           //图片链接
    int64 winnings = 5;             //总奖金
    int32 seats_cur = 6;            //当前报名数
    int32 seats_max = 7;            //最大报名数
    int32 winners = 8;              //有奖励的人数
    UserStatus user_status = 9;    //报名状态
    MatchStatus match_status = 10;  //比赛状态
    int64 entry_fee = 11;           //报名费
    int64 begin_time = 12;          //开赛时间
    int32 svid = 13;                //赛事svid
    int32 del_reg_end = 14;         //距离开赛x秒就不能取消报名退赛了
    MatchType match_type = 15;      //赛事类型
    int64 instance_id = 16;         //整数的赛事实例id
    bool sticky = 17;               //是否置顶
    uint32 chips =18;               //初始筹码
    int32 match_seq = 19;           //赛事顺序
    int64 regist_time = 20;         //开始报名时间
    bool new_player = 21;           //是否新手爽局
    repeated MatchTag match_tag = 22;   //赛事标签
    MatchForm match_form = 23;      //赛事形式
    repeated Prop entry_prop = 24;  //报名需要道具
    int64 regist_end_time = 25;     //结束报名时间
    int32 game_id = 26;             //新手爽局前端处理
    FastMatchInfo fast = 27;        //快速赛
    repeated JointMath joint_match = 28;     //联赛标识
}

message JointMath
{
    uint32 jointmatch_id = 1;
    JointMatchPhase sub_match_phase = 2;             // 联赛阶段:海选赛/初赛/半决赛/决赛/总决赛，取值JointMatchPhase
}

message MatchListResp {
    repeated MatchInfo match_list = 1;
    TagType tag_type = 2;
    int32 push_num = 3;             //剩余推送次数
    int32 game_id = 4;              //游戏id
    int64 srv_tm = 5;               //服务器时间
}

enum RegErrCode {
    SUCCESS = 0;                    //成功
    NOT_IN_REG_TIME = 1;            //不在报名时段内
    ALREADY_REG = 2;                //已经报名了
    ASSET_FAIL = 3;                 //资产不足
    MAX_REG_NUM_OUT = 4;            //超过最大报名人数
    SERVER_ERROR = 5;               //服务器错误
    NOT_IN_DELREG_TIME = 6;         //不在退赛时段内
    NOT_REG = 7;                    //没有报名
    TO_TASK = 8;                    //异常惩罚或者免费次数用完,需要做任务
    FREE_NUM_OUT = 9;               //免费次数用完
    SAME_IP_DEVICE = 10;            //防刷, 相同ip超过5个或者相同设备号超过1个          
    ABNORMAL_ACTION = 11;           //异常行为等级2
    REG_OTHER_PLAYERFULL = 12;      //已经报名了其他人满赛
    REQ_FAST = 13;                  //请求太频繁
    MATCH_CONFIG_CLOSE = 14;        //配置下架
}

