message MatchDetailsResp {
    message LevelInfo { //阶段配置
        //deal
        int32 level = 1;
        int32 tables = 2;
        int32 players = 3;
        int32 promoted = 4;
        //point
        int32 level_time = 5;   //显示对应轮次的有效持续时间分钟
        int64 pt_value = 6;     //显示对应轮次的底分
        int64 qualify = 7;      //显示对应轮次最低筹码要求
        bool rebuy = 8;         //是否能重复买入
        int64 rebuy_price = 9;  //显示对应轮次重复买入的价格, 若对应轮次不能重复买入, 则显示为-
        int64 reload = 10;      //显示对应轮次重复买入后可获得的筹码, 若对应轮次不能重复买入, 则显示为-

        int32 phase_num = 11;   //阶段局数
    }

    message RankInfo { //奖励配置
        string ranks = 1;
        int64 prizes = 2;
        repeated Prop prop = 3;    //奖励的道具
    }

    MatchInfo match_info = 1;
    repeated LevelInfo level_list = 2;
    repeated RankInfo rank_list = 3;
    string rules = 4;           //规则说明
    bool new_player = 5;        //是否新手爽局, 详情界面请求报名使用
    int64 srv_tm = 6;           //服务器时间
    bool rebuy = 7;             // 是否可以重复买入
}


